mapper.update:
UPDATE learning_plan
SET status = #{status},
    title = #{title},
    plan_json = #{planJson, typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE learning_plan
SET title = #{title},
    plan_json = #{planJson, typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    updated_at = #{updatedAt}
WHERE id = #{planId}
  AND user_id = #{userId}

mapper.select:
SELECT COUNT(*)
FROM learning_plan
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM learning_plan
WHERE user_id = #{userId}
  AND status = #{status}

SELECT MAX(created_at)
FROM learning_plan
WHERE user_id = #{userId}

mapper.update:
UPDATE learning_plan_draft
SET confirmed_plan_id = NULL,
    updated_at = NOW()
WHERE user_id = #{userId}
  AND confirmed_plan_id = #{planId}

mapper.delete:
DELETE FROM learning_plan
WHERE id = #{id}
  AND user_id = #{userId}

mapper.update:
UPDATE learning_plan_proposal_group
SET status = #{status},
    initial_instruction = #{initialInstruction},
    latest_proposal_id = #{latestProposalId},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE learning_plan_draft_revision
SET status = #{status},
    instruction = #{instruction},
    base_plan_json = #{basePlanJson, typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    proposed_plan_json = #{proposedPlanJson, typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    error_code = #{errorCode},
    error_message = #{errorMessage},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:
SELECT COALESCE(MAX(revision_no), 0) + 1
FROM learning_plan_draft_revision
WHERE proposal_group_id = #{proposalGroupId}

SELECT COALESCE(MAX(revision_no), 0) + 1
FROM learning_plan_extension_revision
WHERE proposal_group_id = #{proposalGroupId}

UPDATE learning_plan_draft_revision
SET status = 'SUPERSEDED',
    updated_at = #{updatedAt}
WHERE proposal_group_id = #{proposalGroupId}
  AND id != #{exceptRevisionId}
  AND status = 'READY'
RETURNING id

UPDATE learning_plan_extension_revision
SET status = 'SUPERSEDED',
    updated_at = #{updatedAt}
WHERE proposal_group_id = #{proposalGroupId}
  AND id != #{exceptRevisionId}
  AND status = 'READY'
RETURNING id

SELECT COALESCE(MAX(phase_index), 0)
FROM learning_plan_phase
WHERE plan_id = #{planId}
